(180001,'软件界面架构','# 软件界面架构\n\n## 模块一\n- 子模块 A\n- 子模块 B\n\n## 模块二\n- 子模块 C\n- 子模块 D\n',390001,10560002,'2026-07-08 07:06:51','2026-07-08 07:06:51'),
(210001,'SHROOM - 总架构图','# SHROOM\n\n## 📁 SHROOM优化\n\n\n## 📁 密钥--shroom配套\n\n### Key Manager 业务逻辑图\n\n#### 业务总览\n  - 核心对象\n	- 用户账号\n	- 客户\n	- 合同\n	- 在线密钥\n	- 离线密钥\n	- 传感器类型\n	- 设备心跳\n	- 设备报码\n	- 用户反馈\n	- 审计日志\n  - 核心角色\n	- 超级管理员\n	- 管理员\n	- 子账号\n	- 外部设备客户端\n  - 核心闭环\n	- 创建客户\n	- 创建合同\n	- 生成密钥\n	- 客户端激活\n	- 心跳续验\n	- 异常处置\n	- 审计追踪\n\n#### 主业务闭环\n```mermaid\nflowchart TD\n	start[\"业务开始\"] --> login[\"后台登录\"]\n	login --> role{\"角色权限\"}\n\n	role -->|超级管理员| allScope[\"全局数据域\"]\n	role -->|管理员| teamScope[\"本人和下级数据域\"]\n	role -->|子账号| selfScope[\"本人数据域\"]\n\n	allScope --> customer[\"客户管理\"]\n	teamScope --> customer\n	selfScope --> customer\n\n	customer --> contract[\"合同管理\"]\n	contract --> keyGen[\"生成授权密钥\"]\n	keyGen --> deliver[\"交付客户/设备\"]\n	deliver --> activate[\"设备激活校验\"]\n	activate --> heartbeat[\"设备心跳上报\"]\n	heartbeat --> monitor[\"后台监控\"]\n\n	monitor --> normal{\"状态正常?\"}\n	normal -->|是| continueUse[\"继续使用\"]\n	normal -->|否| handle[\"异常处置\"]\n\n	handle --> suspend[\"暂停\"]\n	handle --> renew[\"续期\"]\n	handle --> revoke[\"吊销\"]\n	handle --> clearTamper[\"清除异常\"]\n	handle --> reissue[\"重新签发\"]\n\n	suspend --> audit[\"写入审计\"]\n	renew --> audit\n	revoke --> audit\n	clearTamper --> audit\n	reissue --> audit\n	continueUse --> audit\n```\n\n#### 账号权限\n  - 登录入口\n	- 本地账号密码\n	- OAuth 回调\n	- Session Cookie\n  - 权限分层\n	- 公开接口\n		- 密钥验证\n		- 密钥激活\n		- 服务时间\n		- 传感器列表\n		- 反馈提交\n	- 登录用户\n		- 查看个人数据域\n		- 创建客户\n		- 创建合同\n		- 生成密钥\n		- 查看密钥\n	- 管理员\n		- 管理下级账号\n		- 暂停密钥\n		- 恢复密钥\n		- 吊销密钥\n		- 续期密钥\n		- 查看心跳\n	- 超级管理员\n		- 全量账号\n		- 全量审计\n		- 传感器类型\n		- RSA 密钥对\n		- 密钥类型变更\n  - 数据域\n	- 超级管理员看全部\n	- 管理员看本人和下级\n	- 子账号看本人\n	- 部分账号按传感器分组过滤\n\n#### 账号权限图\n```mermaid\nflowchart LR\n	user[\"请求用户\"] --> auth{\"是否登录\"}\n	auth -->|否| publicOnly[\"只允许公开接口\"]\n	auth -->|是| active{\"账号启用?\"}\n	active -->|否| forbidden[\"拒绝访问\"]\n	active -->|是| role{\"角色\"}\n\n	role --> super[\"super_admin\"]\n	role --> admin[\"admin\"]\n	role --> sub[\"user\"]\n\n	super --> all[\"全局数据\"]\n	admin --> children[\"本人 + 下级\"]\n	sub --> own[\"本人数据\"]\n\n	all --> procedure[\"业务操作\"]\n	children --> procedure\n	own --> procedure\n	publicOnly --> publicApi[\"公开校验/反馈\"]\n```\n\n#### 客户合同流程\n  - 客户管理\n	- 创建客户\n	- 编辑客户\n	- 禁用客户\n	- 删除客户\n	- 删除前检查活跃密钥\n  - 合同管理\n	- 创建合同\n	- 合同编号唯一\n	- 绑定客户\n	- 设置数量额度\n	- 设置合同状态\n	- 删除前检查关联密钥\n  - 合同状态\n	- 草稿\n	- 生效\n	- 过期\n	- 终止\n  - 密钥归属\n	- 绑定客户\n	- 绑定合同\n	- 记录合同编号\n	- 记录创建人\n\n#### 在线密钥流程\n```mermaid\nflowchart TD\n	input[\"填写授权参数\"] --> validate[\"校验参数\"]\n	validate --> sensor[\"选择传感器类型\"]\n	validate --> days[\"设置有效天数\"]\n	validate --> category[\"选择密钥类型\"]\n	validate --> customer[\"选择客户\"]\n	validate --> contract[\"选择合同\"]\n\n	sensor --> generate[\"生成密钥字符串\"]\n	days --> generate\n	category --> generate\n	customer --> save[\"写入 licenseKeys\"]\n	contract --> save\n	generate --> save\n\n	save --> output[\"返回密钥\"]\n	output --> customerDeliver[\"交付客户\"]\n	customerDeliver --> clientCheck[\"客户端校验\"]\n	clientCheck --> decode{\"能否解码\"}\n	decode -->|否| invalid[\"INVALID\"]\n	decode -->|是| dbCheck[\"查询数据库记录\"]\n	dbCheck --> status{\"数据库状态\"}\n\n	status -->|ISSUED| activate[\"首次激活\"]\n	status -->|ACTIVATED| valid[\"继续有效\"]\n	status -->|SUSPENDED| suspended[\"拒绝使用\"]\n	status -->|REVOKED| revoked[\"拒绝使用\"]\n	status -->|TAMPERED| tampered[\"拒绝使用\"]\n	status -->|EXPIRED| expired[\"拒绝使用\"]\n\n	activate --> valid\n	valid --> response[\"返回授权信息\"]\n	suspended --> response\n	revoked --> response\n	tampered --> response\n	expired --> response\n	invalid --> response\n```\n\n#### 密钥生命周期\n  - 初始状态\n	- `ISSUED`\n	- 未激活\n	- 有到期时间\n	- 有创建人\n  - 使用状态\n	- 首次校验激活\n	- 写入激活时间\n	- 绑定设备信息\n	- 返回剩余天数\n  - 管理状态\n	- 暂停\n	- 恢复\n	- 续期\n	- 吊销\n	- 清除异常\n	- 重新签发\n  - 终止状态\n	- 过期\n	- 吊销\n	- 异常\n  - 历史记录\n	- 状态变更\n	- 操作人\n	- 原因\n	- 时间\n	- 审计日志\n\n#### 密钥状态机\n```mermaid\nstateDiagram-v2\n	[*] --> ISSUED: 生成\n	ISSUED --> ACTIVATED: 首次有效校验\n	ISSUED --> EXPIRED: 到期\n	ACTIVATED --> EXPIRED: 到期\n	ACTIVATED --> SUSPENDED: 暂停\n	SUSPENDED --> ACTIVATED: 恢复\n	ACTIVATED --> RENEWED: 续期\n	RENEWED --> ACTIVATED: 继续使用\n	ACTIVATED --> REVOKED: 吊销\n	ISSUED --> REVOKED: 吊销\n	ACTIVATED --> TAMPERED: 时间回拨/篡改\n	TAMPERED --> ACTIVATED: 清除异常\n	TAMPERED --> REVOKED: 重新签发并吊销旧密钥\n	REVOKED --> [*]\n	EXPIRED --> [*]\n```\n\n#### 客户端校验流程\n  - 服务时间\n	- `/serverTime`\n	- 返回服务器毫秒时间\n	- 客户端校时参考\n  - 在线校验\n	- `/licenseCheck`\n	- 校验密钥格式\n	- 解码授权载荷\n	- 查询数据库状态\n	- 检测到期\n	- 检测暂停\n	- 检测吊销\n	- 检测异常\n	- 首次使用激活\n  - 传感器同步\n	- `/sensorTypes`\n	- 返回分组列表\n	- 返回扁平列表\n	- 返回 value-label 映射\n  - 反馈提交\n	- `/feedback`\n	- 公开提交\n	- 内容截断\n	- IP 记录\n	- 后台处理\n\n#### 防篡改流程\n```mermaid\nflowchart TD\n	check[\"客户端校验\"] --> report[\"上报 clientTime / tamper\"]\n	report --> serverNow[\"服务器时间\"]\n	serverNow --> compare{\"是否异常\"}\n	compare -->|否| normal[\"维持原状态\"]\n	compare -->|时间回拨| mark[\"标记 TAMPERED\"]\n	compare -->|客户端上报篡改| mark\n	mark --> deny[\"拒绝授权\"]\n	mark --> reason[\"记录异常原因\"]\n	mark --> list[\"进入异常列表\"]\n	list --> admin{\"管理员处置\"}\n	admin --> clear[\"清除异常\"]\n	admin --> reissue[\"重新签发\"]\n	admin --> revoke[\"吊销旧密钥\"]\n```\n\n#### 离线密钥流程\n  - 生成条件\n	- 机器码\n	- 传感器类型\n	- 有效天数\n	- RSA 密钥对\n  - 签发过程\n	- 获取活跃 RSA 密钥\n	- 生成离线激活码\n	- 写入离线密钥记录\n	- 返回激活码\n  - 客户端验证\n	- 使用公钥\n	- 校验 RSA-SHA256 签名\n	- 校验机器码\n	- 校验到期时间\n  - 后台管理\n	- 离线密钥列表\n	- 离线密钥统计\n	- RSA 密钥对列表\n	- 生成新 RSA 密钥对\n\n#### 设备心跳流程\n```mermaid\nsequenceDiagram\n	participant Device as 设备客户端\n	participant API as heartbeat.ping\n	participant DB as 数据库\n	participant Admin as 后台监控\n\n	Device->>API: keyString + deviceCode + version\n	API->>DB: 查询密钥\n	DB-->>API: 密钥状态\n	API->>API: 判断暂停/吊销/异常/过期\n	alt 授权有效\n		API->>DB: 写入心跳\n		API-->>Device: authorized=true\n	else 授权失效\n		API-->>Device: authorized=false + reason\n	end\n	Admin->>API: 查看心跳列表\n	API->>DB: 查询 keyHeartbeats\n	Admin->>API: 查看丢失设备\n	API->>DB: 按阈值查询超时设备\n```\n\n#### 设备报码流程\n  - 设备类型\n	- 足部设备\n	- 座椅设备\n	- 虚拟设备\n  - 读取记录\n	- 插槽编号\n	- 插槽名称\n	- MAC 地址\n	- 成功状态\n	- 合同编号\n	- 创建人\n  - 列表查看\n	- 按数据域过滤\n	- 按设备类型过滤\n	- 分页查看\n  - 删除规则\n	- 记录存在\n	- 超级管理员可删全部\n	- 非超管只能删本数据域\n\n#### 反馈处理流程\n```mermaid\nflowchart TD\n	submit[\"外部提交反馈\"] --> validate[\"校验内容\"]\n	validate --> type[\"归类类型\"]\n	type --> save[\"写入 feedback\"]\n	save --> list[\"后台反馈列表\"]\n	list --> scope[\"按数据域过滤\"]\n	scope --> status[\"处理状态\"]\n	status --> pending[\"pending\"]\n	status --> processing[\"processing\"]\n	status --> resolved[\"resolved\"]\n	status --> closed[\"closed\"]\n	processing --> remark[\"填写处理备注\"]\n	resolved --> archive[\"完成归档\"]\n	closed --> archive\n```\n\n#### 审计规则\n  - 写入场景\n	- 导出密钥\n	- 创建合同\n	- 更新合同\n	- 删除合同\n	- 暂停密钥\n	- 恢复密钥\n	- 吊销密钥\n	- 续期密钥\n	- 清除异常\n	- 重新签发\n  - 审计字段\n	- 用户 ID\n	- 用户名\n	- 动作类型\n	- 资源类型\n	- 资源 ID\n	- 描述\n	- IP\n	- User-Agent\n  - 查看权限\n	- 超级管理员\n\n#### 业务边界\n  - 删除客户\n	- 检查客户是否存在\n	- 检查活跃密钥数量\n	- 有活跃密钥则阻止\n  - 删除合同\n	- 检查合同是否存在\n	- 检查数据域权限\n	- 检查活跃密钥数量\n	- 有活跃密钥则阻止\n  - 管理账号\n	- 管理员不能创建管理员\n	- 管理员只能操作下级\n	- 非超管不能操作超管\n  - 导出密钥\n	- 按数据域过滤\n	- 按条件过滤\n	- 写入审计日志\n  - 反馈处理\n	- 按数据域过滤\n	- 管理员可删除\n	- 子账号只能处理范围内反馈\n\n#### 页面到业务映射\n  - `Home`\n	- 密钥统计\n	- 异常提醒\n	- 快捷入口\n  - `GenerateKey`\n	- 在线密钥生成\n	- 客户合同绑定\n  - `KeyList`\n	- 密钥查询\n	- 生命周期管理\n	- 导出\n  - `VerifyKey`\n	- 密钥解码\n	- 有效性验证\n  - `OfflineKeyGen`\n	- 离线激活码\n	- RSA 签名\n  - `OfflineKeyList`\n	- 离线记录\n	- 离线统计\n  - `CustomerManagement`\n	- 客户资料\n	- 客户删除约束\n  - `ContractManagement`\n	- 合同资料\n	- 合同删除约束\n  - `HeartbeatMonitor`\n	- 心跳列表\n	- 丢失设备\n  - `TamperedKeys`\n	- 异常密钥\n	- 清除异常\n	- 重新签发\n  - `AuditLog`\n	- 操作审计\n  - `FeedbackManagement`\n	- 反馈处理\n\n\n## 📁 SDK--SHROOM',240001,1,'2026-07-08 07:45:11','2026-07-09 09:01:33'),
